import React, { useEffect, useState } from 'react';
cons [material, setMaterial] = useState([]);

const MaterialList = () => {
  return fetch('http://localhost:8081/')
    .then((res) => res.json())
    .then((d) => setMaterial(d))
  
};

useEffect(() => {
  MaterialList();
})
export default MaterialList;
